#!/usr/bin/env python3

from flask import Flask, jsonify, abort
from bitcoinrpc.authproxy import AuthServiceProxy
import os
import sys

app = Flask(__name__)

# Bitcoin RPC connection configuration
RPC_HOST = os.environ.get('BITCOIN_RPC_HOST', 'localhost')
RPC_PORT = os.environ.get('BITCOIN_RPC_PORT', '8332')
RPC_USER = os.environ.get('BITCOIN_RPC_USER', 'user')
RPC_PASSWORD = os.environ.get('BITCOIN_RPC_PASSWORD', 'pass')

rpc_connection = None
try:
    rpc_connection = AuthServiceProxy(f'http://{RPC_USER}:{RPC_PASSWORD}@{RPC_HOST}:{RPC_PORT}')
    # Test connection
    rpc_connection.getblockchaininfo()
except Exception as e:
    print(f'Failed to connect to Bitcoin RPC: {e}', file=sys.stderr)
    rpc_connection = None

@app.route('/status', methods=['GET'])
def status():
    if rpc_connection is None:
        return jsonify({'status': 'offline', 'error': 'Cannot connect to Bitcoin RPC'}), 200
    try:
        info = rpc_connection.getblockchaininfo()
        return jsonify({'status': 'online', 'blocks': info['blocks'], 'chain': info['chain']})
    except Exception as e:
        return jsonify({'status': 'error', 'error': str(e)}), 500

@app.route('/block/<block_hash>', methods=['GET'])
def block(block_hash):
    if rpc_connection is None:
        return jsonify({'error': 'Bitcoin RPC not available'}), 503
    try:
        block_data = rpc_connection.getblock(block_hash, 2)  # verbosity 2 includes tx details
    except Exception as e:
        # If block not found, RPC throws specific error; we assume 404
        return jsonify({'error': f'Block not found: {e}'}), 404
    # Transform to our schema
    response = {
        'hash': block_data['hash'],
        'height': block_data['height'],
        'merkleroot': block_data['merkleroot'],
        'time': block_data['time'],
        'nonce': block_data['nonce'],
        'tx': [tx['txid'] for tx in block_data['tx']]
    }
    return jsonify(response)

@app.route('/transaction/<txid>', methods=['GET'])
def transaction(txid):
    if rpc_connection is None:
        return jsonify({'error': 'Bitcoin RPC not available'}), 503
    try:
        tx_data = rpc_connection.getrawtransaction(txid, True)  # verbose True
    except Exception as e:
        return jsonify({'error': f'Transaction not found: {e}'}), 404
    # Transform to our schema
    vin = []
    for inp in tx_data.get('vin', []):
        if 'coinbase' in inp:
            vin.append({
                'coinbase': inp['coinbase'],
                'sequence': inp.get('sequence', 0)
            })
        else:
            # For regular inputs, we include txid and vout
            vin.append({
                'txid': inp.get('txid', ''),
                'vout': inp.get('vout', 0),
                'sequence': inp.get('sequence', 0)
            })
    vout = []
    for out in tx_data.get('vout', []):
        vout.append({
            'value': out['value'],
            'n': out['n'],
            'scriptPubKey': out['scriptPubKey']
        })
    response = {
        'txid': tx_data['txid'],
        'blockhash': tx_data.get('blockhash', ''),
        'vin': vin,
        'vout': vout
    }
    return jsonify(response)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)
EOF
